INSERT INTO `posts` (`id`, `title`, `description`, `excerpt`, `feature_img_name`, `feature_img_original_name`, `feature_img_mime`, `feature_img_ext`, `status`, `tags`, `read`, `headline`, `front_slider`, `highlight`, `publish_status`, `published_year`, `published_number`, `published_at`, `slug`, `addedby_id`, `writer_id`, `editedby_id`, `created_at`, `updated_at`) VALUES
(1, '{\"en\":\"Roller Mill\"}', '{\"en\":\"<p><span style=\\\"color: #000000; font-family: \'myriad pro\', Georgia, Times, \'Times New Roman\', serif; font-size: medium; text-align: justify;\\\">Roller mill FMO-7A is used for grinding and crushing of cereal grains. It is designed to obtain flour and semolina in the flour and semolina mills. Automatic adaptation for changeable milling conditions on different passages.<\\/span><\\/p>\"}', '{\"en\":\"Roller mill FMO-7A is used for grinding and crushing of cereal grains. It is designed to obtain flour and semolina in the flour and semolina mills. Automatic adaptation for changeable milling conditions on different passages.\"}', 'roller-mill_611643613257.png', 'spomax.png', NULL, 'png', NULL, '{\"en\":[\"Roller Mill\"]}', 0, 0, 1, 0, 'published', 0, 0, '2022-01-31 07:08:00', 'roller-mill', 1, 1, NULL, '2022-01-31 01:08:30', '2022-01-31 01:14:17'),
(2, '{\"en\":\"Roller\"}', '{\"en\":\"<p><span style=\\\"color: #000000; font-family: \'myriad pro\', Georgia, Times, \'Times New Roman\', serif; font-size: medium; text-align: justify;\\\">FP SPOMAX S.A. is one of the biggest European manufacturers and suppliers of cast iron rolls for the food processing industry. Rolls manufactured by SPOMAX are used for grinding, flaking and cracking products of vegetable and mineral origin.<\\/span><\\/p>\\r\\n<p><span style=\\\"color: #000000; font-family: \'myriad pro\', Georgia, Times, \'Times New Roman\', serif; font-size: medium; text-align: justify;\\\">The self-matting rolls The self-matting rolls are used primarily as milling rolls in the process of grinding wheat and rye. They replace the so-far used smooth rolls. The self-matting rolls can also substitute fine-corrugated rolls on final passages of flour mills. Moreover, they find application in the food industry (manufacturing of spices, condiments, etc.) and feed industry (manufacturing of fodder additives) as well as in chemical and pharmaceutical industry. The working part of self-matting rolls is a centrifugally cast iron sleeve with a special chemical composition and a special microstructure and lowered hardness down to ca. 400 HB. Selfmatting rolls developed by SPOMAX are manufactured from a special alloy and have a surface which stays rough during the lifetime of the roll. Special features of the working layer allow it to keep the required roughness for a long time. The application of self-matting rolls leads to an increase of flour extraction and to improvement of mill profitability. In case of 10 to 12 milling passages, replacing standard rolls with the selfmatting rolls an increase of passage flour extraction up to 2 to 3 percent and about 3 percent increase of total mill capacity has been recorded. Alternatively, by using self-matting rolls it is possible to achieve an increase of milling capacity of up to 5 to 10 percent while retaining the same extraction (higher load of the milling slot) or reduction of the number of milling passages by one or even two passages. Other advantages of the self matting rolls are: they do not get as hot as standard rolls, they ensure much better thermal conductivity as compared with standard rolls, they do not cause the product sticking, their lifetime is longer. Thanks to the application of the self-matting rolls it is possible to obtain a better flour quality as compared with flour production on standard rolls (an increase of bright flour extraction).<\\/span><\\/p>\"}', '{\"en\":\"FP SPOMAX S.A. is one of the biggest European manufacturers and suppliers of cast iron rolls for the food processing industry. Rolls manufactured by SPOMAX are used for grinding, flaking and cracking products of vegetable and mineral origin.\"}', '30101643613026.png', 'Roller.png', NULL, 'png', NULL, '{\"en\":[\"Roller Tag\"]}', 0, 0, 1, 0, 'published', 0, 0, '2022-01-26 07:09:00', 'roller', 1, 1, NULL, '2022-01-31 01:09:20', '2022-02-14 04:22:36'),
(3, '{\"en\":\"Roller Mill - 8A\"}', '{\"en\":\"<p><span style=\\\"color: rgb(0, 0, 0); font-family: &quot;myriad pro&quot;, Georgia, Times, &quot;Times New Roman&quot;, serif; font-size: medium; text-align: justify;\\\">FP SPOMAX S.A. is one of the biggest European manufacturers and suppliers of cast iron rolls for the food processing industry. Rolls manufactured by SPOMAX are used for grinding, flaking and cracking products of vegetable and mineral origin.<\\/span><br><\\/p>\"}', '{\"en\":\"FP SPOMAX S.A. is one of the biggest European manufacturers and suppliers of cast iron rolls for the food processing industry. Rolls manufactured by SPOMAX are used for grinding, flaking and cracking products of vegetable and mineral origin.\"}', NULL, NULL, NULL, NULL, NULL, '{\"en\":[\"Roller Mill - 8A tag\"]}', 0, 1, 1, 1, 'published', 0, 0, '2022-01-31 07:11:00', 'roller-mill-8a', 1, 1, NULL, '2022-01-31 01:10:26', '2022-01-31 01:11:48'),
(4, '{\"en\":\"Roller Mill - HLW\"}', '{\"en\":\"<p><span style=\\\"color: #000000; font-family: \'myriad pro\', Georgia, Times, \'Times New Roman\', serif; font-size: medium; text-align: justify;\\\">FP SPOMAX S.A. is one of the biggest European manufacturers and suppliers of cast iron rolls for the food processing industry. Rolls manufactured by SPOMAX are used for grinding, flaking and cracking products of vegetable and mineral origin.<\\/span><\\/p>\"}', '{\"en\":\"FP SPOMAX S.A. is one of the biggest European manufacturers and suppliers of cast iron rolls for the food processing industry. Rolls manufactured by SPOMAX are used for grinding, flaking and cracking products of vegetable and mineral origin.\"}', 'roller-mill-hlw_401643613213.png', 'Roller Mill - HLW.png', NULL, 'png', NULL, '{\"en\":[\"Roller Mill - HLW\"]}', 0, 0, 1, 0, 'published', 0, 0, '2022-01-31 07:12:00', 'roller-mill-hlw', 1, 1, NULL, '2022-01-31 01:11:48', '2022-01-31 01:13:33'),
(5, '{\"en\":\"Brief Description of Project & Product\"}', '{\"en\":\"<p>Due to huge potentials of the amusement park of Bangladesh and sizeable market, M\\/S SHITALAKHYA WATER KINGDOM has planned to establish a Asumement park named Shitalakhya Water Kingdom. In this park, there will be various types of rides such as Train, Merry-go-Round, Ferris Wheel, Game Zone and Water Park rides. Water park rides will include Speed Boat, Combo Boat, Inflatable Boat, Rib Boat, Barbecue Boat, Bumper Boat, Water Car, Lover boat, Yellow Boat, Tricycle (Double), Tricycle (Single) and Jet Sky. In Water World, there will be rainbow slides, wave pool, water dancing &amp; other rides. Besides, there will also be swimming pool, resort and gymnasium. There will be total Fourty-four (44) rides in which there will be one (01) train, one (01) merry-go-round, one (01) ferris wheel, five (05) Game Zones and thirty (30) others park rides. Besides, there will be twenty (20) cottages and 3 Convention centre and the occupancy rate has been estimated 30.00% in first year with 10.00% growth every year. For restaurant and food court, visitors have been estimated 720,000 per year with 10.00% growth every year and each visitor spending\\/day has been estimated BDT 100.00. Yearly revenue operational days has been estimated 100 days within 360 days.<\\/p>\"}', '{\"en\":\"Due to huge potentials of the amusement park of Bangladesh and sizeable market, M\\/S SHITALAKHYA\\r\\nWATER KINGDOM has planned to establish a Asumement park named Shitalakhya Water Kingdom. In this\\r\\npark, there will be various types of rides such as Train, Merry-go-Round, Ferris Wheel, Game Zone and Water\\r\\nPark rides. Water park rides will include Speed Boat, Combo Boat, Inflatable Boat, Rib Boat, Barbecue Boat,\\r\\nBumper Boat, Water Car, Lover boat, Yellow Boat, Tricycle (Double), Tricycle (Single) and Jet Sky. In Water\\r\\nWorld, there will be rainbow slides, wave pool, water dancing & other rides. Besides, there will also be\\r\\nswimming pool, resort and gymnasium.\"}', 'brief-description-of-project-product_781643628148.png', 'Screenshot 2022-01-31 171842.png', NULL, 'png', NULL, '{\"en\":null}', 0, 0, 1, 0, 'published', 0, 0, '2022-01-31 11:16:00', 'brief-description-of-project-product', 1, 1, NULL, '2022-01-31 01:13:05', '2022-01-31 05:22:28'),
(6, '{\"en\":\"RISK FACTORS AND MANAGEMENT\\u2019S PERCEPTIONS ABOUT THE RISKS\"}', '{\"en\":\"<p>There are risks associated with all investment decision. The investors (Banks\\/ Financial Institutions \\/ Private Equity) should be aware of those risks. These risks could result in loss of income or capital investment. Before making any investment decision the investors should carefully consider the following risks in addition to the information contained in the feasibility report for evaluating the said offer and whether to invest in the project or not. Credit Risk: This is the risk of default on a debt that may arise because of default by the borrower to pay the loan. In operating any business there is always credit risk lies in the business. As there is always lending and borrowing between parties in the form of money and goods. Management Perception: Credit Risk mainly lies with banks and Financial Institutions. Since M\\/S SHITALAKHYA WATER KINGDOM has diversified business expertness and last few years this Concern is running its business operational smoothly with its expert management team,this Concern have good policy to mitigate the credit risk of the business. As M\\/S SHITALAKHYA WATER KINGDOM will take long term and short-term financing from banks or financial institutions, a certain degree of credit risk will lie because of this obligation. The management is well aware of this and management tries to manage it efficiently through continuous supervision Liquidity Risk: The risk that a Concern may be unable to meet short term financial demands. This usually occurs due to the inability to convert its current assets to cash without a loss of capital or income. Liquidity is a common phenomenon of the business. Management Perception: M\\/S SHITALAKHYA WATER KINGDOM has been dealing with its working capital in efficient way to maintain liquidity risk. Management dealing with account payable, inventory and account receivable efficiently. Interest rate risk: Interest rate risk is associated with the fluctuations in market interest rates which cause a Concern&rsquo;s cost of debt to increase. A Concern having significant borrowed fund faces interest rate risks when the rate of interest fluctuates unfavorably due to volatility in money market. Changes in the Government&rsquo;s monetary policy also tend to increase the interest rates. High rate of interest may adversely affect the operating results and financial performance of companies having borrowed fund of significant volume. Increase in the interest rate burdens the Concern with additional financial charges and squeezes the profit of the Concern. Management perception: The management of M\\/S SHITALAKHYA WATER KINGDOM is well aware of the volatility in the money market of country. The Concern believes that rising interest rates will not substantially affect the Concern. However, M\\/S SHITALAKHYA WATER KINGDOM has been repaying borrowed funds on a continuous basis. The management of the Concern emphasizes on equity-based financing to reduce the dependency on borrowings. The management strongly believes that fluctuation of interest rate would have a little impact upon the performance of M\\/S SHITALAKHYA WATER KINGDOM Industry Risks: Industry risk could have an adverse impact on the business, financial condition and results of operation. Risk of volatility of raw material costs: The cost of raw materials &amp; packing materials is volatile. Sometimes, these raw materials price hike due to scarcity of raw materials or artificial demand creation. Management Perception: The management of M\\/S SHITALAKHYA WATER KINGDOM is aware of the continuing market situation of its raw materials.<\\/p>\"}', '{\"en\":\"There are risks associated with all investment decision. The investors (Banks\\/ Financial Institutions \\/ Private\\r\\nEquity) should be aware of those risks. These risks could result in loss of income or capital investment.\\r\\nBefore making any investment decision the investors should carefully consider the following risks in\\r\\naddition to the information contained in the feasibility report for evaluating the said offer and whether to\\r\\ninvest in the project or not.\"}', 'risk-factors-and-managements-perceptions-about-the-risks_371643628362.png', 'Screenshot 2022-01-31 171842.png', NULL, 'png', NULL, '{\"en\":null}', 0, 0, 1, 0, 'published', 0, 0, '2022-01-31 11:23:00', 'risk-factors-and-management-s-perceptions-about-the-risks', 1, 1, NULL, '2022-01-31 05:17:38', '2022-01-31 05:26:02'),
(7, '{\"en\":\"Park Infrastructure\"}', '{\"en\":\"<p>8.1 Land In this project there is Total 9.55 acres owned land. Total land cost has been estimated BDT 667.80 mln.\\r\\n8.2 Park Land Development\\r\\n\\r\\nIn this proposed project, park land development cost has been estimated BDT 11.98 mln. The details are as follows:\\r\\nSitalakhya Amusement Park\\r\\nEstimated Park Land Development\\r\\nFig. in BDT\\r\\nSN. Description\\r\\nTotal\\r\\nAreas\\/Square feet\\r\\nEstimated Cost\\/ Square\\r\\nfeet\\r\\nTotal Estimated Cost\\r\\n1 Wave Pool 226,200 12 2,714,400\\r\\n2 Rainbow Shade 142,800 12 1,713,600\\r\\n3 Train 86,400 12 1,036,800\\r\\n4 Ferris Wheel 11,000 Lump Sum 1,500,000\\r\\n5 Land Development for Road 101,500 Lump Sum 5,014,000\\r\\nTotal 11,978,800\\r\\n\\r\\n8. Park\\r\\nInfrastructur\\r\\ne\\r\\nFeasibility Report and Business Plan\\r\\nOf\\r\\n31\\r\\n8.3 Civil Constructions\\r\\nIn this project, there will be civil works for Wave Pool, Rainbow Slide, Train Counter Civil Works, Ferris Wheel,\\r\\nVR Hall, Game Hall, Swimming Pool with 41 piling for Swimming Pool Zone, Gymnasium, 2- Storied Admin\\r\\nBuilding, Restaurant, Food Court (Open Area) etc. The cost has been estimated BDT 160.87 mln. Other civil\\r\\nworks, fitting &amp; equipment for this project has been estimated BDT 148.24 mln. Cottage Construction Cost\\r\\nhas been estimated BDT 35.00 mln. The breakdown of the civil constructions is given below:\\r\\nShitalakhya Water Kingdom\\r\\nEstimated Civil Works and its Cost\\r\\nFig. in BDT\\r\\nSN. Description\\r\\nTotal\\r\\nAreas\\/Square feet\\r\\nEstimated Cost\\/ Square\\r\\nfeet\\r\\nTotal Estimated Cost\\r\\n1 Wave Pool 18,750 1,500 28,125,000\\r\\n2 DJ Room 2,500 1,500 3,750,000\\r\\n3 Train Counter Civil Works 1,800 1,200 2,160,000\\r\\n4 Lazy River 4,940 1,250 6,175,000\\r\\n5 Convention Hall 10,000 1,500 15,000,000\\r\\n6 Fun House 11,000 2,050 22,550,000\\r\\n7 Swimming Pool Lump Sum 20,000,000\\r\\nPool Zone\\r\\n8 Gymnasium 3,000 2000 6,000,000\\r\\n9 2- Storied Admin Building 5250 1850 9,712,500\\r\\n10 Restaurant 5700 2000 11,400,000\\r\\n11 Food Court (Open Area) 20000 1800 36,000,000\\r\\nTotal 160,872,500\\r\\nFeasibility Report and Business Plan\\r\\nOf\\r\\n32\\r\\nShitalakhya Water\\r\\nKingdom\\r\\nOther Civil works, Fitting and Equipment cost\\r\\nSN. Description Purpose\\r\\nTotal\\r\\nAreas\\/Square fe et\\r\\nEstimated Cost\\/\\r\\nSquare feet\\r\\n1 Boundary Wall\\r\\nFor Wave Pool\\r\\nLump Sum\\r\\n2 Washroom &amp; Changeroom 3,800 1300\\r\\n3 Pipe &amp; Fittings Lump Sum\\r\\n4 Other Civil Works Lump Sum\\r\\n5 Food Court 500 1500\\r\\n6 Paint 37,700 40\\r\\n7 Labour Cost 37,700 180\\r\\nSub-Total\\r\\n1 Boundary Wall\\r\\nRainbow Slide\\r\\nLump Sum\\r\\n2 Water Pond Lump Sum\\r\\n3 Installation Lump Sum\\r\\n4 Other Civil Works\\r\\nSub-Total\\r\\n1 Train Line Development Train\\r\\n24000 1000\\r\\n2 Other Construction &amp; Beautification Lump Sum\\r\\nSub-Total\\r\\n1 Instrument Hire\\r\\nFerris Wheel\\r\\nLump Sum\\r\\n2 Installation Lump Sum\\r\\n3 Instrument Purchase Lump Sum\\r\\n4 Lighting Lump Sum\\r\\n5 Miscellaneous Lump Sum\\r\\nSub-Total\\r\\n1 WaterPipe,Fittings ,ToolsandEquipment(AllA Swimming Pool\\r\\nZone Lump Sum\\r\\nSub-Total\\r\\n1 Gymnasium Equipments and Instruments Gymnasium Lump Sum\\r\\nSub-Total\\r\\n1 Ticket Counter\\r\\nOther\\r\\nLump Sum\\r\\n2 Gate Lump Sum\\r\\n3 Car Parking Lump Sum\\r\\n4 Internal Road Construction(50,000 rft) 50,000 900\\r\\nSub-Total\\r\\nGrand Total\\r\\n\\r\\n8.4 Imported Rides &amp; Equipment\\r\\nInthisproject,therewillbe Imported and local Rides&amp;EquipmentamountedtoBDT100.48mln.\\r\\nThelistofimportedridesandlocaltools &amp; equipment has been given below:\\r\\nFeasibility Report and Business Plan\\r\\nOf\\r\\n33\\r\\nShitalakhya Water\\r\\nKingdom\\r\\nImported Rides &amp; Equipment\\r\\nS.\\r\\nN\\r\\nDescription Cost\\/USD USD Conversion Cost of Ride\\r\\n(BDT)\\r\\n1 Track Train 1 $ 72,941.18 85\\r\\n2 Ocean Shaking Head Flying Chair 1 $ 45,162.35 85\\r\\n3 Arms Self Control Plane 1 $ 19,567.06 85\\r\\n4 Hydraulic Biman Ride Motorize 1 $ 19,567.06 85\\r\\n5 Bumper Car 25 $ 21,176.47 85\\r\\n6 Speed Boat Lake 4 $ 28,235.29 85\\r\\n7 Speed Boat River 2 $ 14,117.65 85\\r\\n8 Water Laser Show House 1 $ 294,117.65 85\\r\\n9 Wove Pool 1 $ 36,258.82 85\\r\\n10 Padel Boat 6 $ 21,176.47 85\\r\\n11 Ice House 1 $ 294,117.65 85\\r\\n12 Cable Car Ride 1 $ 70,588.24 85\\r\\n13 Water &amp; Other Rides 1 $ 200,000.00 85\\r\\nTotal Cost 100,484,000\\r\\nShitalakhya Water\\r\\nKingdom\\r\\nLocal Tools and\\r\\nEquipment\\r\\nS.\\r\\nN\\r\\nDescription Estimated\\r\\nCost(BDT) Remarks\\r\\n1 Water Tank 2,500,000\\r\\n2 Water Pump 3,000,000\\r\\n3\\r\\n4\\r\\nTotal 5,500,000\\r\\nFeasibility Report and Business Plan\\r\\nOf\\r\\n34\\r\\n8.5 Erection and Installation\\r\\nThe machinery will be installed by foreign erectors to be deputed by the machinery suppliers and they\\r\\nwould be assisted by a team of local technicians and workers. Cost of installation including security\\r\\ndeposit for electricity has been estimated at BDT 4 79.00 lac. Erection will be completed in 3 months\\r\\nperiod.\\r\\n8.6 Source of Power\\/ Energy\\r\\nThe estimated actual powerrequirement for operation of Process Machinery and Auxiliary Equipment of the\\r\\nproject shall be .75 KW (Actual consumption\\/hr. average) against 1.00 W plant capacity which will be\\r\\ntaken from national grid. In addition, Diesel Gen sets (duel fuel provisioning) have been kept as backup\\r\\nduring failure of grid power<br><\\/p>\"}', '{\"en\":\"Land & Land Development, Civil Constructions, Rides, Power & Utilities\"}', '12501643628522.png', 'Screenshot 2022-01-31 171842.png', NULL, 'png', NULL, '{\"en\":null}', 0, 1, 1, 1, 'published', 0, 0, '2022-01-31 11:27:00', 'park-infrastructure', 1, 1, NULL, '2022-01-31 05:24:46', '2022-01-31 05:28:42'),
(8, '{\"en\":\"FINANCIAL ANALYSIS OF THE PROPOSED PROJECT\"}', '{\"en\":\"<p>Particulars 1st Year 2nd Year 3rd Year 4th Year 5th Year Sales Revenue from Entry Fee 18,000 21,600 25,920 28,512 31,363 Sales Revenue from Rides, Water Park &amp; Water World 253,168 253,168 253,168 253,168 253,168 Sales Revenue from Cottage 8,640 11,520 14,400 17,280 20,160 Sales Revenue from Restaurant &amp; food Court 36,000 43,200 51,840 57,024 62,726 Revenue from Convention Centre 81,000 113,400 129,600 145,800 162,000 Net Sales 396,808 442,888 474,928 501,784 529,418<\\/p>\"}', '{\"en\":\"Particulars 1st Year 2nd Year 3rd Year 4th Year 5th Year Sales Revenue from Entry Fee 18,000 21,600 25,920 28,512 31,363 Sales Revenue from Rides, Water Park & Water World 253,168 253,168 253,168 253,168 253,168 Sales Revenue from Cottage 8,640 11,520 14,400 17,280 20,160 Sales Revenue from Restaurant & food Court 36,000 43,200 51,840 57,024 62,726 Revenue from Convention Centre 81,000 113,400 129,600 145,800 162,000 Net Sales 396,808 442,888 474,928 501,784 529,418\"}', '39741643628779.png', 'Screenshot 2022-01-31 171842.png', NULL, 'png', NULL, '{\"en\":null}', 0, 0, 1, 0, 'published', 0, 0, '2022-01-31 11:29:00', 'financial-analysis-of-the-proposed-project', 1, 1, NULL, '2022-01-31 05:28:42', '2022-02-14 23:55:07'),
(9, '{\"en\":\"Transports\"}', '{\"en\":\"<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM bucket elevators - distinguishing features<\\/span><\\/h2>\\r\\n<table style=\\\"margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; border-spacing: 0px; max-width: 100%; background-color: #ffffff; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify;\\\" width=\\\"100%\\\">\\r\\n<tbody style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\" width=\\\"2%\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" width=\\\"98%\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Single or double-sided (symmetrical) drive.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The advantage of the double-sided drive is the even load of the device and the convenience of servicing<\\/span><\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM clutchless direct drive guarantees reliable operation of the lifts<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Helical-bevel gearmotor mounted by a torque arm<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Spherical roller bearing instead of ball bearing<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Mechanical brake to prevent the belt from backing up, also with full buckets<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Optimized shape of the head for better guidance of the grain to discharge<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Safety system: rotation, slip and belt break sensor as standard<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<\\/tbody>\\r\\n<\\/table>\\r\\n<p>&nbsp;<\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Intelligent control system for horizontal and vertical grain transport - what is it?<\\/span><\\/h2>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The system optimizes the speed of the equipment for the transported material as well as its density.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The optimal speed of the transporting devices is obtained with the use of a frequency converter.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The optimal efficiency is obtained by measuring the current and adjusting the speed on the preceding device in the process line.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Application<\\/span><\\/h2>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Bucket elevators are designed for vertical transport of cereal grains, loose materials, fine and light grains and in pieces, from a lower level to a higher one.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Bucket elevators are used for transporting grain in drying and storage facilities, for loading flat halls and warehouses, as well as for collecting grain from receiving baskets.<\\/span><\\/span><\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The most important features of vertical grain transport<\\/span><\\/h2>\\r\\n<table style=\\\"margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; border-spacing: 0px; max-width: 100%; background-color: #ffffff; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify;\\\" width=\\\"100%\\\">\\r\\n<tbody style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" colspan=\\\"2\\\" valign=\\\"top\\\"><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">The most important features of vertical grain transport<\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;:<\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\" width=\\\"2%\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" width=\\\"98%\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Capacity from 30 to 300 t \\/ h<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Equipped with a four- or five-belt conveyor belt and pressed buckets<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Safety system: sensor of rotation, slip and broken belts as standard<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Self-supporting structure of the lift, requires only lateral bracing<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The wear-resistant material used in places exposed to abrasion increases the durability of the device and reduces damage to the transported grain<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Made of galvanized steel sheet (2-3 mm)<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Inspection window in the drive station<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<\\/tbody>\\r\\n<tbody style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Quiet operation of the device, only the noise of the pouring grain is audible<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<\\/tbody>\\r\\n<\\/table>\\r\\n<p>&nbsp;<\\/p>\\r\\n<table style=\\\"margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; border-spacing: 0px; max-width: 100%; background-color: #ffffff; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify;\\\" width=\\\"100%\\\">\\r\\n<tbody style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" colspan=\\\"2\\\" valign=\\\"top\\\"><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">Additional equipment of the bucket elevator<\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;:<\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\" width=\\\"2%\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">1.<\\/span><\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" width=\\\"98%\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Belt alignment sensor<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">2.<\\/span><\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Service platform<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">3.<\\/span><\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">External communication (ladders and landings)<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">4.<\\/span><\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Side emergency refill<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<\\/tbody>\\r\\n<\\/table>\"}', '{\"en\":\"FEERUM bucket elevators - distinguishing features\"}', 'transports_951644824951.jpg', '248892865_1341328823003887_2371429631831995283_n.jpg', NULL, 'jpg', NULL, '{\"en\":null}', 0, 1, 1, 1, 'published', 0, 0, '2022-01-31 11:35:00', 'grain-protection-and-safety', 1, NULL, NULL, '2022-01-31 05:32:59', '2022-02-14 01:49:11');
INSERT INTO `posts` (`id`, `title`, `description`, `excerpt`, `feature_img_name`, `feature_img_original_name`, `feature_img_mime`, `feature_img_ext`, `status`, `tags`, `read`, `headline`, `front_slider`, `highlight`, `publish_status`, `published_year`, `published_number`, `published_at`, `slug`, `addedby_id`, `writer_id`, `editedby_id`, `created_at`, `updated_at`) VALUES
(10, '{\"en\":\"Automation\"}', '{\"en\":\"<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">In FEERUM drying and storage units, we offer&nbsp;<\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">intelligent, fully automatic control of the<\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;multi-stage process of receiving, cleaning, drying and storing grain.<\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The system constantly monitors the properties of the stored grain and its flow, so it not only informs about the occurrence of any irregularities, but also adjusts the operating parameters of individual elements of the assembly in order to avoid failure, prevent overheating of the grain or stop the entire process.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Supervision over the operation of the drying and storage facility can be carried out by only one operator. The entire system operation can be monitored remotely using a computer or smartphone.<\\/span><\\/span><\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Online service<\\/span><\\/h2>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We are responsible for the design, construction from scratch and commissioning of the drying and storage team, and above all, we take care of it all the time, also after the warranty period has expired. The online monitoring system in case of any problem, allows our service technicians to remotely diagnose the situation and help solve any problem.<\\/span><\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We share knowledge<\\/span><\\/h2>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We conduct training for the operators of our facilities before their commissioning and, if necessary, during their many years of work.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The developed solutions are the work of our automation and electricians.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">They are always ready to modify the system in accordance with the individual needs of the client.<\\/span><\\/span><\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We are the innovation leader<\\/span><\\/h2>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">In cooperation with leading research centers, we constantly improve our products.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We design, test and implement unique, innovative and patent-protected solutions.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We use our own&nbsp;<\\/span><\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">Research and Development Center<\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;for this - all products are thoroughly tested here before they are offered to our customers.<\\/span><\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Reliable electrician<\\/span><\\/h2>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">In FEERUM control cabinets, we use high-quality components from Eaton Electric.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">All devices are protected with appropriately selected devices preventing overloads and short circuits.<\\/span><\\/span><\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Temperature monitoring<\\/span><\\/h2>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">In order to increase the safety of the stored grain, in FEERUM silos we use temperature monitoring based on Dallas sensors.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The number of sensors depends on the diameter of the silo.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Readings from certified probes are transferred to the facility control application, which allows for automatic initiation of grain ventilation in the silo.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The readings from the probes can also be archived.<\\/span><\\/span><\\/p>\"}', '{\"en\":\"In FEERUM drying and storage units, we offer intelligent, fully automatic control of the multi-stage process of receiving, cleaning, drying and storing grain.\"}', 'automation_801644824065.jpg', '248892865_1341328823003887_2371429631831995283_n.jpg', NULL, 'jpg', NULL, '{\"en\":null}', 0, 1, 1, 1, 'published', 0, 0, '2022-01-13 11:39:00', 'feerum-has-launched-another-facility-for-epicentr-k', 1, 1, NULL, '2022-01-31 05:35:29', '2022-02-14 01:34:25'),
(11, '{\"en\":\"Cleaners\"}', '{\"en\":\"<p><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The FEERUM treatment plant cleans and calibrates grains and various types of loose materials (including sowing).&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">It is used to separate from the native material: large (straw, spikelets, stones), small and heavy (sand, small seeds of weeds) and light (chaff, dust, etc.).<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We offer five types of cleaners with a capacity of 40, 75, 100, 150 and 200 tons of grain per hour of initial cleaning.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Additional equipment of the FEERUM cleaner:<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">1. Control panel with an inverter<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">2. Aspiration of the sieve drum<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">3. Cyclone<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">4. Fan<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 13.8662px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">5. Air channels<\\/span><\\/span><\\/p>\"}', '{\"en\":\"The FEERUM treatment plant cleans and calibrates grains and various types of loose materials (including sowing). It is used to separate from the native material: large (straw, spikelets, stones), small and heavy (sand, small seeds of weeds) and light (chaff, dust, etc.).\"}', 'cleaners_151644823977.jpg', '248892865_1341328823003887_2371429631831995283_n.jpg', NULL, 'jpg', NULL, '{\"en\":null}', 0, 1, 1, 1, 'published', 0, 0, '2022-01-31 11:40:00', 'sales-increase-and-very-good-financial-results-after-the-first-quarter-of-2020', 1, 1, NULL, '2022-01-31 05:37:42', '2022-02-14 01:32:57'),
(12, '{\"en\":\"Drying rooms\"}', '{\"en\":\"<div class=\\\"post-content\\\" style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM is a leading producer of grain dryers.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The company\'s offer includes dryers operating in a continuous and batch cycle.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">They are intended for drying all types of cereals, including corn, rape, wheat and other seeds, legumes and oilseeds.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Thanks to the appropriate structure and the possibility of adjusting the drying parameters to the grain properties, our dryers achieve high performance indicators with low fuel consumption.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM has patented the most effective and, at the same time, extremely energy-saving process of two-stage drying of corn at low temperature.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The innovative method of drying ensures&nbsp;<\\/span><\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">the safety of grain<\\/span><\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;, preserves its&nbsp;<\\/span><\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">quality and nutritional value<\\/span><\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;, and speeds up the entire process.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We are constantly&nbsp;<\\/span><\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">improving<\\/span><\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;our products!&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The introduction of the air recirculation process (directing warm air after the drying process back over the burner) allowed to reduce gas consumption by 20%.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">A novelty is a drying room with recuperation, i.e. heat recovery, using the so-called&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">cross-flow exchanger.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Thanks to the use of an appropriate construction, we have achieved utility savings of 30%.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM dryers are fully automatically controlled.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The intuitive control panel provides convenience and full control of the drying process.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">In addition, we offer the possibility of online control using a computer, tablet or even a phone.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM dryers are made of galvanized steel sheet or, on special request, of another material (e.g. stainless steel).&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The devices have an arrangement of vertical exhaust fans that reduce noise.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">As standard, we use insulation of the drying column, which has a significant impact on reducing drying costs.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We install a rocker chute in all dryers, which enables precise determination of the volume of the material discharged and its regulation.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 13.8662px; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM dryers can work continuously throughout the harvest season.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The hopper capacity of the dryer ranges from 19 to 329 tons.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We offer dryers fired with natural gas, liquid gas, light fuel oil.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Additionally, the dryer can be supported by a heat exchanger (biomass, biogas plant).&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM dryers work on modulating gas strip burners, modulating oil or two-stage (so-called pistol) burners.<\\/span><\\/span><\\/div>\"}', '{\"en\":\"FEERUM is a leading producer of grain dryers. The company\'s offer includes dryers operating in a continuous and batch cycle. They are intended for drying all types of cereals, including corn, rape, wheat and other seeds, legumes and oilseeds. Thanks to the appropriate structure and the possibility of adjusting the drying parameters to the grain properties, our dryers achieve high performance indicators with low fuel consumption.\"}', 'drying-rooms_201644823647.jpg', '248892865_1341328823003887_2371429631831995283_n.jpg', NULL, 'jpg', NULL, '{\"en\":null}', 0, 1, 1, 1, 'published', 0, 0, '2022-01-01 11:40:00', 'feerum-s-a-comment-regarding-changes-to-contracts-with-epicentr-k-llc', 1, 1, NULL, '2022-01-31 05:40:07', '2022-02-14 01:27:27'),
(13, '{\"en\":\"General contracting\"}', '{\"en\":\"<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: large;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Design, General Contractor and support in obtaining EU subsidies.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We carry out most of the projects as the General Contractor - we offer our clients comprehensive service from the conception, through design work, obtaining administrative permits, construction and assembly, to the final handover of the facility for use.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We offer professional support and advice at every stage of the investment.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We approach each project with full commitment.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We design and implement investments in the general contracting system for domestic and foreign clients.<\\/span><\\/span><\\/p>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Our recipe for success is the effective division of roles.<\\/span><\\/p>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The FEERUM staff includes design engineers and constructors who, in consultation with Regional Sales Managers, develop the proper project and visualizations that meet the highest expectations of customers.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We adapt projects to geographical conditions (ground and seismic), creating the best technological solutions.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We work with a design office that has all the permissions necessary to create structures around the world.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We offer the most effective systems for storing, transporting, loading and unloading grain.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Comprehensive agricultural industry plants are our specialty, confirmed by 20 years of experience.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We will show you how to get a subsidy, e.g. from EU funds.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We have experience in this process supported by several dozen implementations.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" \\/><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">As a General Contractor, we take full responsibility for the construction of a drying and storage complex together with a mill or a feed mixing plant.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The FEERUM Investment Implementation Department ensures that the warehouse complex is built according to the planned, proven schedule.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">He monitors the adopted deadlines and coordinates all industries on the construction site.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The DRI department is also in constant contact with the Production Department, the Procurement Department, as well as with construction inspectors, construction manager, state administration institutions, assembly and construction groups.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Thanks to our innovative solutions in facility control, commissioning and commissioning is only a formality,<\\/span><\\/span><\\/p>\\r\\n<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">General Contractor of FEERUM includes in particular:<\\/span><\\/p>\\r\\n<table style=\\\"margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; border-spacing: 0px; max-width: 100%; background-color: #ffffff; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify;\\\" width=\\\"100%\\\">\\r\\n<tbody style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\" width=\\\"2%\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" width=\\\"98%\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">preparation of the concept of the facility individually tailored to the client\'s needs<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">assistance or power of attorney in obtaining a building permit<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">execution of a construction project<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">earth and foundation works<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">production and transport of elements to the construction site<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">assembly of devices<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">conducting tests and trial run<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">implementation of a drying and storage complex and handing it over to use<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">training for staff operating the facility<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<tr style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\" valign=\\\"top\\\">\\r\\n<ul>\\r\\n<li style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">&nbsp;<\\/li>\\r\\n<\\/ul>\\r\\n<\\/td>\\r\\n<td style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">warranty and post-warranty service<\\/span><\\/td>\\r\\n<\\/tr>\\r\\n<\\/tbody>\\r\\n<\\/table>\"}', '{\"en\":\"Design, General Contractor and support in obtaining EU subsidies.\"}', 'from-idea-to-profit_701644823112.jpg', '248892865_1341328823003887_2371429631831995283_n.jpg', NULL, 'jpg', NULL, '{\"en\":null}', 0, 0, 1, 0, 'published', 0, 0, '2022-02-12 06:47:00', 'grain-protection-and-safety-2', 1, 1, NULL, '2022-01-31 05:41:24', '2022-02-14 01:22:07');
INSERT INTO `posts` (`id`, `title`, `description`, `excerpt`, `feature_img_name`, `feature_img_original_name`, `feature_img_mime`, `feature_img_ext`, `status`, `tags`, `read`, `headline`, `front_slider`, `highlight`, `publish_status`, `published_year`, `published_number`, `published_at`, `slug`, `addedby_id`, `writer_id`, `editedby_id`, `created_at`, `updated_at`) VALUES
(14, '{\"en\":\"Silos\"}', '{\"en\":\"<p style=\\\"box-sizing: border-box; margin: 0px 0px 10px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-size: 1.0833em; line-height: 1.6666; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">FEERUM silos are used for long and short-term storage of grain,&nbsp;<\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1;\\\">mainly cereals, including maize and oilseeds<\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We produce flat-bottom, hopper, forwarding, square, feed and non-standard silos at the customer\'s request.<\\/span><\\/span><\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Construction for years<\\/span><\\/h2>\\r\\n<p><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We design silos with a diameter of 1.9 to 33.4 m and we manufacture them from corrugated galvanized steel sheets.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The use of corrugated sheet reduces the heating of the silo from sunlight,&nbsp;<\\/span><\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">provides a more durable structure and guarantees a longer service life of the silo.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">The strength<\\/span><\\/span><\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;of the silo structure is additionally increased by the method of mounting the side covers on the so-called&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">brick, where the lower plating layer is tied by the upper plating shifted by half its length.<\\/span><\\/span><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff;\\\" \\/><br style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff;\\\" \\/><\\/p>\\r\\n<h2 style=\\\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; font-family: Lato, Arial, Helvetica, sans-serif; font-weight: normal; line-height: 1.25em; color: #2d3e52; font-size: 1.6667em; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">High temperature resistant silo<\\/span><\\/h2>\\r\\n<p><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">In silos, we use ventilators, electric or gravity fans, thanks to which we minimize the process of water condensation under the roof in the event of temperature differences between the interior of the silo and its surroundings.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">We have also developed a silo ventilation system that cools and aerates the grain at the same time.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">In addition, thanks to the temperature monitoring system,&nbsp;<\\/span><\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">we can observe the temperature of the grain online, keeping it in a state that prevents the development of biological processes.&nbsp;<\\/span><\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">Fully automated FEERUM drying and storage facilities are equipped with&nbsp;<\\/span><\\/span><strong style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">intelligent<\\/span><\\/strong><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; color: #21323a; font-family: Lato, Arial, Helvetica, sans-serif; font-size: 12.8px; text-align: justify; background-color: #ffffff; vertical-align: inherit;\\\"><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">&nbsp;online management systems.&nbsp;<\\/span><span style=\\\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: transparent; zoom: 1; vertical-align: inherit;\\\">They are reliable and perform well in all geographic and climatic conditions.<\\/span><\\/span><\\/p>\"}', '{\"en\":\"FEERUM silos are used for long and short-term storage of grain, mainly cereals, including maize and oilseeds . We produce flat-bottom, hopper, forwarding, square, feed and non-standard silos at the customer\'s request.\"}', 'silos_901644823867.jpg', '248892865_1341328823003887_2371429631831995283_n.jpg', NULL, 'jpg', NULL, '{\"en\":null}', 0, 1, 1, 1, 'published', 0, 0, '2022-02-10 06:48:00', 'epicentr-agro-built-a-grain-elevator-in-wapniarka-with-a-capacity-of-200-thousand-tons-of-simultaneous-storage-with-energy-saving-equipment', 1, 1, NULL, '2022-02-01 00:47:31', '2022-02-14 01:31:07'),
(15, '{\"en\":\"What is LPG conversion?\"}', '{\"en\":\"<p>LPG, which stands for Liquefied Petroleum Gas, is a convenient energy source used for many purposes, including heating, cooking, as well as vehicle fuel.<\\/p>\\r\\n<p>An LPG conversion is taking a normal petrol-powered vehicle and adding a secondary LPG vehicle fuel system. These dual-fuel LPG systems allow an LPG vehicle to operate on either LPG or petrol. The petrol tank remains in the LPG vehicle. The driver can switch from gas to petrol or vice-versa.<\\/p>\"}', '{\"en\":\"LPG, which stands for Liquefied Petroleum Gas, is a convenient energy source used for many purposes, including heating, cooking, as well as vehicle fuel.\"}', 'autoverde-lpg-conversion-kits_851643701524.jpeg', 'LPG-conversion-picture.jpeg', NULL, 'jpeg', NULL, '{\"en\":null}', 0, 1, 1, 1, 'published', 0, 0, '2022-02-02 07:43:00', 'autoverde-lpg-conversion-kits', 1, 1, NULL, '2022-02-01 00:49:22', '2022-02-12 04:58:17'),
(16, '{\"en\":\"31 conferences and fairs of the International Association of Millers of the Region\"}', '{\"en\":\"<p><span style=\\\"font-family: &quot;Segoe UI Historic&quot;, &quot;Segoe UI&quot;, Helvetica, Arial, sans-serif; white-space: pre-wrap; background-color: rgb(255, 255, 255);\\\"><font color=\\\"#000000\\\" style=\\\"\\\">We are very pleased to announce that FP Spomax S.A. actively participated in 31 conferences and fairs of the International Association of Millers of the Region: the Middle East and Africa (IAOM MEA). The event was organized in Dubai on October 10-12, 2021. Our company has aroused a lot of interest from global industry companies there. We are convinced that the results of the talks will soon translate into specific commercial contracts.<\\/font><\\/span><br><\\/p>\"}', '{\"en\":\"We are very pleased to announce that FP Spomax S.A. actively participated in 31 conferences and fairs of the International Association of Millers of the Region: the Middle East and Africa (IAOM MEA).\"}', '53291644664029.jpg', '248892865_1341328823003887_2371429631831995283_n.jpg', NULL, 'jpg', NULL, '{\"en\":null}', 0, 1, 1, 1, 'published', 0, 0, '2022-02-12 11:04:00', '31-conferences-and-fairs-of-the-international-association-of-millers-of-the-region', 1, NULL, NULL, '2022-02-01 01:44:26', '2022-02-12 05:07:09'),
